from pymongo import MongoClient

# Connect to the MongoDB server
client = MongoClient('mongodb://localhost:27017/')

# Select the database and collection
db = client['mydatabase']
collection = db['mycollection']

# Get user-provided filter expression
filter_expression = input("Enter your filter expression: ")

# Execute the JavaScript expression using $where operator
results = collection.find({'$where': filter_expression})

# Print the results
for result in results:
    print(result)